<?php
namespace Tests\Feature\Hr;
use App\Models\HrLicense; use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class AdvancePagesTest extends TestCase { use RefreshHrDatabase; public function test_advance_pages_render():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$user=User::factory()->create(['role_id'=>$role]);$this->actingAs($user);$tenant=LegalEntity::create(['user_id'=>$user->id,'name'=>'Avans','tax_number'=>'3434343434','is_active'=>true]);app(TenantContext::class)->set($tenant);HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$tenant->id,'user_id'=>$user->id,'employee_number'=>'ADVP','national_id_encrypted'=>'enc','national_id_hash'=>'adv-p','national_id_last_four'=>'0001','first_name'=>'Avans','last_name'=>'Sayfa','status'=>'active']);HrLicense::create(['legal_entity_id'=>$tenant->id,'module_key'=>'avans','is_active'=>true]);$this->get(route('hr.advances'))->assertOk()->assertSee('Avans Yönetimi');$this->get(route('hr.my-advances'))->assertOk()->assertSee('Avanslarım');} }
